<?php
$pageTitle = 'Backup Manager';
$pageDescription = 'Stonefellow production backup and restore readiness dashboard.';
$pageClass = 'membership-page admin-catalog-page';
require __DIR__ . '/../includes/admin_catalog.php';
require_once __DIR__ . '/../includes/backup_release.php';
sf_sec_require('admin.settings.manage');
if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST') {
  $action=(string)($_POST['action']??'');
  if($action==='create_run'){ $id=sf_br_create_run($_POST); sf_admin_flash($id?'success':'error',$id?'Backup record created.':'Backup record not created. Run migration 019.'); sf_admin_redirect($id?sf_url('admin/backups.php?backup_id='.$id):null); }
  if($action==='update_run'){ sf_br_update_run((int)($_POST['backup_id']??0),$_POST); sf_admin_flash('success','Backup record updated.'); }
  if($action==='update_check'){ sf_br_update_check((int)($_POST['check_id']??0),(string)($_POST['status']??'pending'),(string)($_POST['detail']??'')); sf_admin_flash('success','Readiness check updated.'); }
  sf_admin_redirect(sf_url('admin/backups.php'.(!empty($_POST['backup_id'])?'?backup_id='.(int)$_POST['backup_id']:'')));
}
require __DIR__ . '/../includes/header.php';
$summary=sf_br_summary();
$profiles=sf_br_profiles();
$runs=sf_br_runs(120);
$selectedId=(int)($_GET['backup_id']??($runs[0]['id']??0));
$selected=$selectedId?sf_br_run($selectedId):null;
$checks=$selectedId?sf_br_restore_checks($selectedId):[];
$manifest=$selected&&!empty($selected['manifest_json'])?json_decode((string)$selected['manifest_json'],true):sf_br_manifest();
sf_admin_shell_start('Backup Manager', 'Backup and restore readiness v1', 'Track backup records, readiness checks, schema manifests, media/storage coverage, and pre-release safety status.', 'backups');
?>
<section class="sf-admin-card-grid">
  <div class="sf-admin-action-card"><span>Profiles</span><strong><?= (int)$summary['profiles'] ?></strong><small>Backup profiles.</small></div>
  <div class="sf-admin-action-card"><span>Runs</span><strong><?= (int)$summary['runs'] ?></strong><small>Total records.</small></div>
  <div class="sf-admin-action-card"><span>Completed</span><strong><?= (int)$summary['completed'] ?></strong><small>Completed records.</small></div>
  <div class="sf-admin-action-card"><span>Verified</span><strong><?= (int)$summary['verified'] ?></strong><small>Verified records.</small></div>
  <a class="sf-admin-action-card" href="<?= sf_url('admin/releases.php') ?>"><span>Releases</span><strong><?= (int)$summary['ready_releases'] ?></strong><small>Ready/draft releases.</small></a>
</section>
<section class="sf-admin-two-col sf-admin-two-col-wide">
  <article class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Backup Records</span><h2><?= count($runs) ?> records</h2></div><a href="<?= sf_url('api/backup-manager.php') ?>">JSON API</a></div><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Run</th><th>Profile</th><th>Status</th><th>DB</th><th>Uploads</th><th>Config</th></tr></thead><tbody><?php foreach($runs as $run): ?><tr><td><strong><a href="<?= sf_url('admin/backups.php?backup_id='.(int)$run['id']) ?>"><?= sf_admin_h($run['run_key']) ?></a></strong><small><?= sf_admin_h($run['created_at']) ?></small></td><td><?= sf_admin_h($run['profile_label'] ?: 'Manual') ?></td><td><?= sf_admin_status_badge($run['run_status']) ?></td><td><?= sf_admin_h($run['database_status']) ?></td><td><?= sf_admin_h($run['uploads_status']) ?></td><td><?= sf_admin_h($run['config_status']) ?></td></tr><?php endforeach; ?><?php if(!$runs): ?><tr><td colspan="6">No backup records yet.</td></tr><?php endif; ?></tbody></table></div></article>
  <aside class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Create Record</span><h2>Backup checklist</h2></div></div><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="create_run"><label>Profile<select name="profile_id"><option value="0">Manual / no profile</option><?php foreach($profiles as $p): ?><option value="<?= (int)$p['id'] ?>"><?= sf_admin_h($p['profile_label']) ?></option><?php endforeach; ?></select></label><div class="sf-admin-form-grid"><label>Run Type<?= sf_admin_select('run_type',['manual'=>'Manual','scheduled'=>'Scheduled','pre_release'=>'Pre-release','post_release'=>'Post-release'],'manual') ?></label><label>Status<?= sf_admin_select('run_status',['planned'=>'Planned','running'=>'Running','completed'=>'Completed','failed'=>'Failed','verified'=>'Verified','archived'=>'Archived'],'planned') ?></label></div><label>Location / Reference<input name="storage_location" placeholder="Manual archive reference"<?= sf_admin_form_disabled_attr() ?>></label><label>Notes<textarea name="notes" rows="4"<?= sf_admin_form_disabled_attr() ?>></textarea></label><div class="sf-admin-form-actions"><button type="submit"<?= sf_admin_form_disabled_attr() ?>>Create Record</button></div></form></aside>
</section>
<?php if($selected): ?><section class="sf-admin-two-col sf-admin-two-col-wide"><article class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Selected Record</span><h2><?= sf_admin_h($selected['run_key']) ?></h2></div></div><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="update_run"><input type="hidden" name="backup_id" value="<?= (int)$selected['id'] ?>"><div class="sf-admin-form-grid"><label>Status<?= sf_admin_select('run_status',['planned'=>'Planned','running'=>'Running','completed'=>'Completed','failed'=>'Failed','verified'=>'Verified','archived'=>'Archived'],$selected['run_status']) ?></label><label>Database<?= sf_admin_select('database_status',['not_started'=>'Not Started','exported'=>'Exported','skipped'=>'Skipped','failed'=>'Failed','verified'=>'Verified'],$selected['database_status']) ?></label></div><div class="sf-admin-form-grid"><label>Uploads<?= sf_admin_select('uploads_status',['not_started'=>'Not Started','exported'=>'Exported','skipped'=>'Skipped','failed'=>'Failed','verified'=>'Verified'],$selected['uploads_status']) ?></label><label>Config<?= sf_admin_select('config_status',['not_started'=>'Not Started','exported'=>'Exported','skipped'=>'Skipped','failed'=>'Failed','verified'=>'Verified'],$selected['config_status']) ?></label></div><label>Location / Reference<input name="storage_location" value="<?= sf_admin_h($selected['storage_location']??'') ?>"<?= sf_admin_form_disabled_attr() ?>></label><label>Notes<textarea name="notes" rows="4"<?= sf_admin_form_disabled_attr() ?>><?= sf_admin_h($selected['notes']??'') ?></textarea></label><div class="sf-admin-form-actions"><button type="submit"<?= sf_admin_form_disabled_attr() ?>>Update Record</button></div></form></article><aside class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Readiness Checks</span><h2><?= count($checks) ?> checks</h2></div></div><div class="sf-admin-list"><?php foreach($checks as $check): ?><article class="sf-admin-list-row"><strong><?= sf_admin_h($check['check_label']) ?></strong><span><?= sf_admin_h($check['check_group']) ?> · <?= sf_admin_h($check['status']) ?></span><form class="sf-admin-inline-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="update_check"><input type="hidden" name="backup_id" value="<?= (int)$selected['id'] ?>"><input type="hidden" name="check_id" value="<?= (int)$check['id'] ?>"><button name="status" value="passed" type="submit">Pass</button><button name="status" value="failed" type="submit">Fail</button><button name="status" value="waived" type="submit">Waive</button></form></article><?php endforeach; ?></div></aside></section><section class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Manifest</span><h2>Schema snapshot</h2></div></div><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Database Table</th><th>Rows</th></tr></thead><tbody><?php foreach(array_slice($manifest['database_tables']??[],0,80) as $t): ?><tr><td><?= sf_admin_h($t['table']??'') ?></td><td><?= (int)($t['rows']??0) ?></td></tr><?php endforeach; ?></tbody></table></div></section><?php endif; ?>
